def getMaxRepetitions(s1: str, n1: int, s2: str, n2: int) -> int:
    max_repetitions = 0
    for i in range(n1):
        for j in range(n2):
            if s1[:j] == s2[:j]:
                max_repetitions = max(max_repetitions, len(s1) - j)
    return max_repetitions

